function approval_billing_table_delete($selected_id, $AllowDeleteOfParents = false, $skipChecks = false) {
	// insure referential integrity ...
	global $Translation;
	$selected_id = makeSafe($selected_id);

	// mm: can member delete record?
	if(!check_record_permission('approval_billing_table', $selected_id, 'delete')) {
		return $Translation['You don\'t have enough permissions to delete this record'];
	}

	// hook: approval_billing_table_before_delete
	if(function_exists('approval_billing_table_before_delete')) {
		$args = [];
		if(!approval_billing_table_before_delete($selected_id, $skipChecks, getMemberInfo(), $args))
			return $Translation['Couldn\'t delete this record'] . (
				!empty($args['error_message']) ?
					'<div class="text-bold">' . strip_tags($args['error_message']) . '</div>'
					: ''
			);
	}

	// delete file stored in the 'attach_bill_1' field
	$res = sql("SELECT `attach_bill_1` FROM `approval_billing_table` WHERE `id`='{$selected_id}'", $eo);
	if($row = @db_fetch_row($res)) {
		if($row[0] != '') {
			@unlink(getUploadDir('') . $row[0]);
		}
	}

	// delete file stored in the 'attach_bill_2' field
	$res = sql("SELECT `attach_bill_2` FROM `approval_billing_table` WHERE `id`='{$selected_id}'", $eo);
	if($row = @db_fetch_row($res)) {
		if($row[0] != '') {
			@unlink(getUploadDir('') . $row[0]);
		}
	}

	// delete file stored in the 'attach_bill_3' field
	$res = sql("SELECT `attach_bill_3` FROM `approval_billing_table` WHERE `id`='{$selected_id}'", $eo);
	if($row = @db_fetch_row($res)) {
		if($row[0] != '') {
			@unlink(getUploadDir('') . $row[0]);
		}
	}

	sql("DELETE FROM `approval_billing_table` WHERE `id`='{$selected_id}'", $eo);

	// hook: approval_billing_table_after_delete
	if(function_exists('approval_billing_table_after_delete')) {
		$args = [];
		approval_billing_table_after_delete($selected_id, getMemberInfo(), $args);
	}

	// mm: delete ownership data
	sql("DELETE FROM `membership_userrecords` WHERE `tableName`='approval_billing_table' AND `pkValue`='{$selected_id}'", $eo);
}

